def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        scale_factor = 1.0
        if usage_ratio > 2.0:
            priority += 2000 * usage_ratio
            scale_factor = 1.2
            for m in range(1, 7):
                if usage_ratio > (1 + m * 0.12):
                    priority += m * 70 / scale_factor
                else:
                    priority -= m * 25 * scale_factor
        elif 1.2 <= usage_ratio <= 2.0:
            priority += 150 * usage_ratio
            wave_sum = 0.0
            for n in range(5):
                wave_sum += np.sin(n * usage_ratio * np.pi * 0.8) * (n + 1) * 3
            priority += wave_sum
            if 1.5 < usage_ratio < 1.8:
                priority -= (usage_ratio - 1.5) * 40
            else:
                priority += 10
        else:
            diff = 1 - usage_ratio
            if diff <= 0:
                diff = 1e-20
            try:
                log_val = np.log(diff)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -1.0:
                priority += (-log_val) * 12
            else:
                priority += (-log_val) * 3
            extra_factor = 0.0
            for j in range(1, 7):
                power = usage_ratio ** j
                if power < 0.3:
                    extra_factor += power * 15 / (j + 1)
                elif power < 0.6:
                    extra_factor += (0.7 - power) * 10 / (j + 3)
                else:
                    extra_factor -= power * 7 / (j + 2)
            priority += extra_factor
            if capacity < 0.05:
                priority += 100
                if usage_ratio > 0.85:
                    priority += 50
                elif usage_ratio < 0.12:
                    priority -= 30
            elif capacity < 0.35:
                priority += 40
                if usage_ratio > 0.9:
                    priority += 25
                elif usage_ratio < 0.18:
                    priority -= 15
            else:
                if usage_ratio < 0.2:
                    priority -= 10
                elif usage_ratio > 0.9:
                    priority += 50
                else:
                    priority += 7
        prox_score = 0
        if int(capacity * 1000) % 5 == 0:
            prox_score += 6
        if int(capacity * 10000) % 11 == 0:
            prox_score -= 5
        for k in range(1, 6):
            target = k / 6
            diff = abs(usage_ratio - target)
            if diff < 0.05:
                prox_score += 14 / k
            elif diff < 0.12:
                prox_score += 8 / (k + 1)
        for l in range(3, 7):
            mod_check = int(capacity * 1000 * l)
            if mod_check % 13 == 0:
                prox_score -= l * 4
            else:
                if l % 2 == 0:
                    prox_score += l * 1.5
                else:
                    prox_score += l
        for x in range(1, 4):
            oscillation = np.cos(priority * x * 2.718) * 0.7
            priority += oscillation / (x + 1)
        if capacity < 0.2 and usage_ratio > 1.1:
            priority -= np.exp(-capacity * 20) * 60
        noise = np.sin(priority * 3.141592653589793) * 0.7
        priority += noise
        priorities[idx] = priority
    return priorities
